def tipo_di_punto(nome, campi, srid_map):
    """
    Crea dinamicamente una sottoclasse di Point.
    """
    from shapely.geometry import Point

    class Punto(Point):
        def __init__(self, *args, **kwargs):
            super().__init__(*args, **kwargs)
            self.nome = nome
            for campo in campi:
                setattr(self, campo, kwargs.get(campo, None))
            self.srid = srid_map.get(nome, None)

        def __repr__(self):
            return f"{self.nome}({self.x}, {self.y}, SRID={self.srid})"

    return Punto

