def differenza(d1, d2, livello=-1):
    import copy

    def differenza_interna(d1, d2, livello):
        risultato = {}
        for chiave in d1:
            if chiave not in d2:
                risultato[chiave] = copy.deepcopy(d1[chiave])
            else:
                if isinstance(d1[chiave], dict) and isinstance(d2[chiave], dict):
                    if livello != 0:
                        sotto_risultato = differenza_interna(d1[chiave], d2[chiave], livello - 1)
                        if sotto_risultato:
                            risultato[chiave] = sotto_risultato
                elif d1[chiave] != d2[chiave]:
                    risultato[chiave] = copy.deepcopy(d1[chiave])
        return risultato

    return differenza_interna(d1, d2, livello)

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages

def _valida_etichette(etichette):
    espressione_regolare_chiave = r'^[a-zA-Z0-9_]+$'
    espressione_regolare_valore = r'^[a-zA-Z0-9_]+$'
    errori = []

    for chiave, valore in etichette.items():
        if not isinstance(chiave, str) or not re.match(espressione_regolare_chiave, chiave):
            errori.append({chiave: f"Label key '{chiave}' does not match the regex [...]"})

        if isinstance(valore, str):
            if not re.match(espressione_regolare_valore, valore):
                errori.append({valore: 'expected string or bytes-like object'})
        else:
            errori.append({str(valore): 'expected string or bytes-like object'})

    if errori:
        raise ValidationError(errori)

def formatta(
                self,
                sql: AnyStr,
                parametri: Union[Dict[Union[str, int], Any], Sequence[Any]],
        ) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    """
    Converte la query SQL per utilizzare i parametri in stile "out" invece dei parametri in stile "in".

    **sql** (:class:`str` o :class:`bytes`) è la query SQL.

    Restituisce una :class:`tuple` contenente:

    - La query SQL formattata (:class:`str` o :class:`bytes`).

    - L'insieme dei parametri convertiti in stile "out" (:class:`dict` o :class:`list`).
    """
    if isinstance(sql, bytes):
        sql_formattato = sql.decode('utf-8')
    else:
        sql_formattato = sql

    parametri_out = {}

    if isinstance(parametri, dict):
        for chiave, valore in parametri.items():
            parametri_out[chiave] = valore
            sql_formattato = sql_formattato.replace(f":{chiave}", f"${chiave}")
    elif isinstance(parametri, list):
        for indice, valore in enumerate(parametri):
            parametri_out[indice] = valore
            sql_formattato = sql_formattato.replace(f":{indice}", f"${indice}")

    return sql_formattato, parametri_out

def ottieni_mappa_percorsi_logici(inventario, versione):
    """
    Ottiene una mappa dei percorsi logici nello stato verso i file su disco per una determinata versione nell'inventario.

    Restituisce un dizionario: `logical_path_in_state -> set(content_files)`

    Il set di `content_files` può includere riferimenti a file duplicati presenti in versioni successive rispetto alla versione descritta.
    """
    mappa_percorsi = {}

    for file in inventario:
        if file['version'] <= versione:
            percorso_logico = file['logical_path']
            if percorso_logico not in mappa_percorsi:
                mappa_percorsi[percorso_logico] = set()
            mappa_percorsi[percorso_logico].add(file['content_file'])

    return mappa_percorsi

